    }

    private fun validateIntent(intent: Intent?): Boolean {
        if (intent == null) return false
        
        val action = intent.action
        val type = intent.type
        
        // Only accept specific share actions
        if (action != Intent.ACTION_SEND && action != Intent.ACTION_SEND_MULTIPLE) {
            return false
        }
        
        // Validate type is present
        if (type.isNullOrBlank()) {
            return false
        }
        
        return true
    }

    private fun handleIncomingShare(intent: Intent) {
        when (intent.action) {
            Intent.ACTION_SEND -> {
                if (intent.type?.startsWith("text/") == true) {
                    handleSharedText(intent)
                } else if (intent.type?.startsWith("image/") == true) {
                    handleSharedImage(intent)
                } else {
                    showError("Unsupported content type")
                }
            }
            Intent.ACTION_SEND_MULTIPLE -> {
                if (intent.type?.startsWith("image/") == true) {
                    handleSharedImages(intent)
                } else {
                    showError("Unsupported content type")
                }
            }
            else -> {
                showError("Unsupported action")
            }
        }
    }

    private fun handleSharedText(intent: Intent) {
        val sharedText = intent.getStringExtra(Intent.EXTRA_TEXT)
        
        if (sharedText.isNullOrBlank()) {
            showError("No text content found")
            return
        }
        
        // Validate and sanitize the shared text
        val sanitizedText = sanitizeText(sharedText)
        
        if (isValidUrl(sanitizedText)) {
            processUrl(sanitizedText)
        } else {
            processText(sanitizedText)
        }
    }

    private fun handleSharedImage(intent: Intent) {
        val imageUri = intent.getParcelableExtra<Uri>(Intent.EXTRA_STREAM)
        
        if (imageUri == null) {
            showError("No image found")
            return
        }
        
        if (!validateImageUri(imageUri)) {
            showError("Invalid or unsafe image")
            return
        }
        
        processImage(imageUri)
    }

    private fun handleSharedImages(intent: Intent) {
        val imageUris = intent.getParcelableArrayListExtra<Uri>(Intent.EXTRA_STREAM)
        
        if (imageUris.isNullOrEmpty()) {
            showError("No images found")
            return
        }
        
        // Limit number of images
        if (imageUris.size > 10) {
            showError("Too many images. Maximum 10 allowed")
            return
        }
        
        val validUris = imageUris.filter { validateImageUri(it) }
        
        if (validUris.isEmpty()) {
            showError("No valid images found")
            return
        }
        
        processImages(validUris)
    }

    private fun sanitizeText(text: String): String {
        // Remove potential script injections and limit length
        return text.take(10000).trim()
    }

    private fun isValidUrl(text: String): Boolean {
        if (text.length > 2048) return false
        
        // Validate URL pattern
        if (!Patterns.WEB_URL.matcher(text).matches()) {
            return false
        }
        
        // Only allow http and https schemes
        val uri = Uri.parse(text)
        val scheme = uri.scheme?.lowercase()
        
        return scheme == "http" || scheme == "https"
    }

    private fun validateImageUri(uri: Uri): Boolean {
        try {
            // Validate URI scheme - only accept content:// URIs
            if (uri.scheme != "content") {
                return false
            }
            
            // Validate MIME type
            val mimeType = contentResolver.getType(uri)
            if (mimeType == null || !ALLOWED_IMAGE_TYPES.contains(mimeType)) {
                return false
            }
            
            // Validate file size
            contentResolver.openInputStream(uri)?.use { inputStream ->
                val size = getStreamSize(inputStream)
                if (size > MAX_FILE_SIZE) {
                    return false
                }
            } ?: return false
            
            // Grant temporary read permission
            grantUriPermission(packageName, uri, Intent.FLAG_GRANT_READ_URI_PERMISSION)
            
            return true
        } catch (e: SecurityException) {
            return false
        } catch (e: Exception) {
            return false
        }
    }

    private fun getStreamSize(inputStream: InputStream): Long {
        var size = 0L
        val buffer = ByteArray(8192)
        var read: Int
        while (inputStream.read(buffer).also { read = it } != -1) {
            size += read
            if (size > MAX_FILE_SIZE) {
                break
            }
        }
        return size
    }

